from fastapi import FastAPI, Request, Form, HTTPException, status
from fastapi.responses import HTMLResponse, JSONResponse
from fastapi.templating import Jinja2Templates

# Initialize the FastAPI application
app = FastAPI(
    title="Cyberpunk Login Backend",
    description="A FastAPI application for a cyberpunk-themed login page.",
    version="1.0.0"
)

# Configure Jinja2 templating
# The templates directory is assumed to be 'backend/templates' relative to the project root
templates = Jinja2Templates(directory="backend/templates")

@app.get("/", response_class=HTMLResponse)
async def read_root(request: Request):
    """
    Serves the main login page.
    The login page is rendered using Jinja2 template engine.
    """
    return templates.TemplateResponse(
        name="index.html",
        context={
            "request": request,
            "title": "Cyberpunk Login"
        }
    )

@app.post("/login")
async def login(
    username: str = Form(..., description="The user's unique identifier"),
    password: str = Form(..., description="The user's password")
) -> JSONResponse:
    """
    Handles user login by receiving form data (username and password).
    Implements placeholder authentication logic. If credentials match predefined values,
    a success JSON response is returned. Otherwise, an HTTPException with 401 Unauthorized
    status is raised.
    """
    # Placeholder authentication logic
    # In a real application, this would involve hashing passwords, querying a database,
    # and potentially generating authentication tokens (e.g., JWT).
    if username == "user" and password == "password":
        return JSONResponse(
            status_code=status.HTTP_200_OK,
            content={
                "message": "Login successful",
                "detail": f"Welcome, {username}!"
            }
        )
    else:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid credentials",
            headers={"WWW-Authenticate": "Bearer"}
        )
